import { writeOutput } from "./codegen";

const DOCS_URL = "https://developers.zoom.us/docs/api/";
// Zoom OAuth access token — opaque string, no fixed prefix or length.
// Picked a ~60-char value matching typical Zoom JWT-like opaque tokens.
const PLACEHOLDER_VALUE =
  "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocal";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Zoom API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:zoom",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const zoomFirewall = {",
    '  name: "zoom",',
    '  description: "Zoom API",',
    "  placeholders: {",
    `    ZOOM_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.zoom.us",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.ZOOM_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Zoom firewall config...");
  const ts = generateTypeScript();
  writeOutput("zoom", ts, import.meta.dirname);
}
